// src\components\ContactMe\ContactText.tsx

import React from "react";
import { motion } from "framer-motion";
import { useInView } from "react-intersection-observer";
import { usePortfolioContent } from "@/lib/portfolioContent";

// Variantes de animación para contenedor e ítems
const containerVariants = {
  hidden: {},
  show: {
    transition: {
      staggerChildren: 0.1, // Aparece secuencial
    },
  },
};

const itemVariants = {
  hidden: { opacity: 0, scale: 0.9, x: -20 },
  show: {
    opacity: 1,
    scale: 1,
    x: 0,
    transition: { type: "spring", stiffness: 120, damping: 10 },
  },
};

const ContactText: React.FC = () => {
  const { ui } = usePortfolioContent();
  const { ref, inView } = useInView({
    threshold: 0.2,
    triggerOnce: false,
  });
  const hasLongTitle = ui.contact.title.replace(/\s/g, "").length > 8;
  const titleClassName = hasLongTitle
    ? "custom-contactme custom-contactme--compact font-cor text-dar"
    : "custom-contactme font-cor text-dar";

  return (
    <>
      {/* Contact title */}
      <motion.div
        ref={ref}
        variants={containerVariants}
        initial="hidden"
        animate={inView ? "show" : "hidden"}
        className="col-start-2 col-span-5 row-start-2 flex items-center justify-center overflow-hidden px-4"
      >
        <motion.h1
          variants={itemVariants}
          className={titleClassName}
        >
          {ui.contact.title}
        </motion.h1>
      </motion.div>

      {/* Contact subtitle */}
      <motion.div
        ref={ref}
        variants={containerVariants}
        initial="hidden"
        animate={inView ? "show" : "hidden"}
        className="col-start-2 col-span-2 row-start-3 flex items-center"
      >
        <motion.h2
          variants={itemVariants}
          className="custom-contactmail font-lat text-dar"
        >
          {ui.contact.subtitle}
        </motion.h2>
      </motion.div>
    </>
  );
};

export default ContactText;
